			wantSystem: ReadinessSystemReasonQuota,
			wantTriage: "quota",
		},
		{
			name:       "transport",
			detail:     "transport failed: connection reset by peer",
			wantSystem: ReadinessSystemReasonTransport,
			wantTriage: "transport",
		},
		{
